fn run() {
    input! {
        n: usize,
        m: usize,
    }
    let ans = if n == m {
        0
    } else if m <= 1 {
        1
    } else if m <= n / 2 {
        m
    } else {
        n - m
    };
    println!("{}", ans);
}

fn main() {
    run();
